import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Ads Attribution","description":"","frontmatter":{"title":"Ads Attribution","slug":"ads-attribution"},"headers":[],"relativePath":"marketer-hub/ads-attribution.md","filePath":"marketer-hub/ads-attribution.md"}'),o={name:"marketer-hub/ads-attribution.md"};function n(l,e,s,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<p>.png &quot;adnetwork-01.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch gives you the power to connect touchpoints from every channel with conversions on any platform. User journeys happen across channels. To get accurate attribution, you need to measure all of them. Fortunately, Branch has been powering flawless cross-channel user experiences for years, which means our links have a proven track record of working everywhere.</p><p>Using Branch Ads, you gain unique, cross-platform insights into the data you need to get ahead.</p><h3 id="ads-attribution-use-cases" tabindex="-1">Ads Attribution Use Cases <a class="header-anchor" href="#ads-attribution-use-cases" aria-label="Permalink to &quot;Ads Attribution Use Cases&quot;">​</a></h3><ul><li><p>Connect with every ad network for running app campaigns through pre-configured integrations.</p><ul><li><a href="./self-attributing-networks-sans.html">Self-Attributing Networks</a></li><li><a href="./universal-ad-partner-integration-guide.html">Non-Self-Attributing Networks</a></li></ul></li><li><p>Measure app install and re-engagement campaigns for both clicks and views/impressions</p></li><li><p>Long-term trends, broken down by platform, ad set name, channel, and more.</p></li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li>Branch connects with your ad networks for running app campaigns.</li><li>User sees an ad to download app.</li><li>User installs the app and converts.</li><li>Branch communicates with the ad networks to determine which ad network will receive credit for the install/conversion.</li><li>The Branch Dashboard will update reports for you to be able to compare and measure ad campaigns across platforms, ad set name, ad partner, etc.</li></ol><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to Branch Ads requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h2 id="integration-guide" tabindex="-1">Integration Guide <a class="header-anchor" href="#integration-guide" aria-label="Permalink to &quot;Integration Guide&quot;">​</a></h2><h3 id="self-attributing-networks" tabindex="-1">Self-Attributing Networks <a class="header-anchor" href="#self-attributing-networks" aria-label="Permalink to &quot;Self-Attributing Networks&quot;">​</a></h3><ul><li><p><a href="./apple-search-ads.html">Apple Ads</a></p></li><li><p><a href="./facebook-ads-overview.html">Facebook Ads Overview</a></p><ul><li><a href="./facebook-app-install-ads.html">Facebook App Install Ads</a></li><li><a href="./facebook-traffic-and-conversion-ads.html">Facebook Traffic and Conversion Ads</a></li><li><a href="./facebook-platform-ads.html">Facebook Platform Ads</a></li><li><a href="./facebook-faq-and-advanced-options.html">Facebook FAQ and Advanced Options</a></li></ul></li><li><p><a href="./google-ads.html">Google Ads Overview</a></p><ul><li><a href="./enable-google-app-campaigns.html">Enabling the Google Ads Integration</a></li><li><a href="./google-ads-discrepancies.html">Google Ads Reporting and Discrepancies</a></li></ul></li><li><p><a href="./google-marketing-platform.html">Google Marketing Platform Overview</a></p><ul><li><a href="./doubleclick-legacy.html">Doubleclick (Legacy)</a></li></ul></li><li><p><a href="./snap.html">Snap</a></p></li><li><p><a href="./twitter-ads.html">Twitter Ads</a></p></li><li><p><a href="./yahoo-ads.html">Yahoo Ads</a></p></li></ul><h3 id="non-self-attributing-networks" tabindex="-1">Non-Self-Attributing Networks <a class="header-anchor" href="#non-self-attributing-networks" aria-label="Permalink to &quot;Non-Self-Attributing Networks&quot;">​</a></h3><p>Please view <a href="./universal-ad-partner-integration-guide.html">this guide</a> on integrating Branch with Non-Self-Attributing Networks.</p>',15)])])}const f=a(o,[["render",n]]);export{p as __pageData,f as default};
